55	// Atomic text write: temp + fsync + rename, so a reader always sees either the
56	// previous complete file or the new one (a crash mid-write never leaves a
57	// half-written registry or dashboard). Mirrors the runtime writeStateAtomic
58	// contract for the markdown dashboard, which the JSON-only runtime helper cannot
59	// serialize.
60	function writeTextAtomic(filePath, content) {
61	  fs.mkdirSync(path.dirname(filePath), { recursive: true });
62	  const tempPath = `${filePath}.tmp.${process.pid}.${crypto.randomBytes(6).toString('hex')}`;
63	  let fd;
64	  try {
65	    fs.writeFileSync(tempPath, content, 'utf8');
66	    fd = fs.openSync(tempPath, 'r');
67	    fs.fsyncSync(fd);
68	    fs.closeSync(fd);
69	    fd = undefined;
70	    fs.renameSync(tempPath, filePath);
71	    // Best-effort parent-directory fsync so the rename itself is durable after a
72	    // crash (mirrors the runtime writeStateAtomic; the inline fallback previously
73	    // synced only the file, not the directory entry).
74	    try {
75	      const dirFd = fs.openSync(path.dirname(filePath), 'r');
76	      try { fs.fsyncSync(dirFd); } finally { fs.closeSync(dirFd); }
77	    } catch { /* best-effort: some platforms disallow directory fsync */ }
78	  } catch (error) {
79	    if (typeof fd === 'number') { try { fs.closeSync(fd); } catch { /* already closed */ } }
80	    if (fs.existsSync(tempPath)) { fs.rmSync(tempPath, { force: true }); }
81	    throw error;
82	  }
83	}
