89	// Truncate a corrupt JSONL tail in place: keep every complete valid line, drop
90	// trailing garbage from a crash mid-append. Contract-equivalent to the runtime
91	// repairJsonlTail, used as the fallback when the TS toolchain is unavailable.
92	function repairJsonlTailInline(filePath) {
93	  if (!fs.existsSync(filePath)) return { repaired: false, droppedBytes: 0 };
94	  const content = fs.readFileSync(filePath, 'utf8');
95	  if (content.length === 0) return { repaired: false, droppedBytes: 0 };
96	  const originalBytes = Buffer.byteLength(content, 'utf8');
97	  let cursor = 0;
98	  let validEnd = 0;
99	  const newlineRe = /\r?\n/g;
100	  while (cursor < content.length) {
101	    newlineRe.lastIndex = cursor;
102	    const match = newlineRe.exec(content);
103	    if (!match) break;
104	    const lineEnd = match.index;
105	    const rawLine = content.slice(cursor, lineEnd);
106	    const nextCursor = lineEnd + match[0].length;
107	    if (rawLine.trim() !== '') {
108	      try { JSON.parse(rawLine); } catch { break; }
109	    }
110	    validEnd = nextCursor;
111	    cursor = nextCursor;
112	  }
113	  const trailing = content.slice(cursor);
114	  let keepBytes;
115	  if (trailing.trim() === '') {
116	    keepBytes = originalBytes;
117	  } else {
118	    try { JSON.parse(trailing); keepBytes = originalBytes; }
119	    catch { keepBytes = Buffer.byteLength(content.slice(0, validEnd), 'utf8'); }
120	  }
121	  const droppedBytes = originalBytes - keepBytes;
122	  if (droppedBytes <= 0) return { repaired: false, droppedBytes: 0 };
123	  fs.truncateSync(filePath, keepBytes);
124	  return { repaired: true, droppedBytes };
125	}
