186	/**
187	 * Parse JSONL content into an array of records. Corrupt lines are reported, not
188	 * silently dropped, so a partial run surfaces rather than hides truncation.
189	 *
190	 * @param {string} jsonlContent - Newline-delimited JSON string
191	 * @returns {{records: Array<Object>, corruptionWarnings: Array<{line:number, length:number, sha256:string, error:string}>}}
192	 */
193	function parseJsonlDetailed(jsonlContent) {
194	  const records = [];
195	  const corruptionWarnings = [];
196	  let lineNumber = 0;
197	
198	  for (const rawLine of String(jsonlContent || '').split('\n')) {
199	    lineNumber += 1;
200	    const line = rawLine.trim();
201	    if (!line) {
202	      continue;
203	    }
204	    try {
205	      records.push(JSON.parse(line));
206	    } catch (error) {
207	      corruptionWarnings.push({
208	        line: lineNumber,
209	        // Never persist raw content — a malformed record may carry secrets. Report
210	        // length + a short content hash so corruption is diagnosable without leakage.
211	        length: line.length,
212	        sha256: crypto.createHash('sha256').update(line).digest('hex').slice(0, 12),
213	        error: error instanceof Error ? error.message : String(error),
214	      });
215	    }
216	  }
217	
218	  return { records, corruptionWarnings };
219	}
220	
221	function parseJsonl(jsonlContent) {
222	  return parseJsonlDetailed(jsonlContent).records;
223	}
