231	function validateSeatFinding(raw) {
232	  if (!raw || typeof raw !== 'object') return 'finding is not an object';
233	  const kind = normalizeText(raw.kind) || 'reuse_candidate';
234	  if (!VALID_FINDING_KINDS.has(kind)) return `unknown kind "${kind}"`;
235	  if (!normalizeText(raw.path) && !normalizeText(raw.symbol)) return 'missing both path and symbol';
236	  if (raw.relevance != null && !Number.isFinite(Number(raw.relevance))) return 'non-numeric relevance';
237	  return null;
238	}
