250	  const findings = [];
251	  const seatLabels = [];
252	  const failedSeats = [];
253	  const validationWarnings = [];
254	  if (!fs.existsSync(iterDir)) {
255	    return { findings, seatLabels, failedSeats, validationWarnings };
256	  }
257	
258	  const seatFiles = fs.readdirSync(iterDir)
259	    .filter((name) => name.endsWith('.json'))
260	    .sort((a, b) => a.localeCompare(b, undefined, { numeric: true }));
