268	
269	    if (!Array.isArray(seatFindings)) {
270	      failedSeats.push(label);
271	      continue;
272	    }
273	    seatLabels.push(label);
274	    for (const raw of seatFindings) {
275	      const reason = validateSeatFinding(raw);
276	      if (reason) {
277	        validationWarnings.push({
278	          seat: label,
279	          reason,
280	          symbol: raw && typeof raw === 'object' ? normalizeText(raw.symbol) : '',
281	          path: raw && typeof raw === 'object' ? normalizeText(raw.path) : '',
282	        });
283	        continue;
284	      }
285	      findings.push({ ...raw, producedBy: label });
