292	/**
293	 * Walk all iteration directories under {seat_dir} and collect every seat finding
294	 * with its iteration number and producing seat label.
295	 *
296	 * @param {string} seatDir - {artifact_dir}/seats absolute path
297	 * @returns {{findings: Array<Object>, seatsByIteration: Object, allSeatLabels: Set<string>}}
298	 */
299	function collectAllSeatFindings(seatDir) {
300	  const findings = [];
301	  const seatsByIteration = {};
302	  const allSeatLabels = new Set();
303	  const validationWarnings = [];
304	  if (!fs.existsSync(seatDir)) {
305	    return { findings, seatsByIteration, allSeatLabels, validationWarnings };
306	  }
307	
308	  const iterDirs = fs.readdirSync(seatDir)
309	    .filter((name) => /^iter-\d+$/.test(name))
310	    .sort((a, b) => a.localeCompare(b, undefined, { numeric: true }));
311	
312	  for (const dirName of iterDirs) {
313	    const iteration = Number(dirName.match(/iter-(\d+)/)[1]);
314	    const { findings: iterFindings, seatLabels, failedSeats, validationWarnings: iterWarnings } = loadSeatFindings(path.join(seatDir, dirName));
315	    seatsByIteration[iteration] = { succeeded: seatLabels, failed: failedSeats };
316	    for (const label of seatLabels) {
317	      allSeatLabels.add(label);
318	    }
319	    for (const warning of iterWarnings) {
320	      validationWarnings.push({ ...warning, iteration });
321	    }
322	    for (const finding of iterFindings) {
323	      findings.push({ ...finding, iteration });
