334	/**
335	 * Dedup raw seat findings by unit_id, union per-executor attribution, and set
336	 * agreement = count of distinct executors that produced the unit.
337	 *
338	 * @param {Array<Object>} rawFindings - Per-seat findings tagged with producedBy + iteration
339	 * @returns {Array<Object>} Deduped units with producedBy[], agreement, relevance, kind, etc.
340	 */
341	function dedupByUnit(rawFindings) {
342	  const byUnit = new Map();
343	
344	  for (const finding of rawFindings) {
345	    const kind = normalizeText(finding.kind) || 'reuse_candidate';
346	    const pathValue = normalizeText(finding.path);
347	    const symbol = normalizeText(finding.symbol);
348	    // Trust an explicit unit_id when present; otherwise derive it deterministically.
349	    const id = typeof finding.unit_id === 'string' && finding.unit_id.trim()
350	      ? finding.unit_id.trim()
351	      : unitId(pathValue, symbol, kind);
352	    const relevance = toNumber(finding.relevance, 0);
353	    const producer = normalizeText(finding.producedBy) || 'unknown';
354	
355	    if (!byUnit.has(id)) {
356	      byUnit.set(id, {
357	        unit_id: id,
358	        path: pathValue,
359	        symbol,
360	        kind,
361	        signature: normalizeText(finding.signature),
362	        reuse: normalizeText(finding.reuse),
363	        evidence: normalizeText(finding.evidence),
364	        notes: normalizeText(finding.notes),
365	        producedBy: [],
366	        relevanceByProducer: {},
367	        signatureByProducer: {},
368	        reuseByProducer: {},
369	        firstIteration: isFiniteNumber(finding.iteration) ? finding.iteration : 0,
370	        maxRelevance: relevance,
371	      });
372	    }
373	
374	    const unit = byUnit.get(id);
375	    if (!unit.producedBy.includes(producer)) {
376	      unit.producedBy.push(producer);
377	    }
378	    unit.relevanceByProducer[producer] = relevance;
379	    unit.signatureByProducer[producer] = normalizeText(finding.signature);
380	    unit.reuseByProducer[producer] = normalizeText(finding.reuse);
381	    unit.maxRelevance = Math.max(unit.maxRelevance, relevance);
382	    if (isFiniteNumber(finding.iteration)) {
383	      unit.firstIteration = Math.min(unit.firstIteration, finding.iteration);
384	    }
385	    // Prefer a non-empty signature/evidence/notes from any producer.
386	    if (!unit.signature && normalizeText(finding.signature)) unit.signature = normalizeText(finding.signature);
387	    if (!unit.evidence && normalizeText(finding.evidence)) unit.evidence = normalizeText(finding.evidence);
388	    if (!unit.notes && normalizeText(finding.notes)) unit.notes = normalizeText(finding.notes);
389	    if (!unit.reuse && normalizeText(finding.reuse)) unit.reuse = normalizeText(finding.reuse);
390	  }
391	
392	  return Array.from(byUnit.values()).map((unit) => ({
393	    ...unit,
394	    agreement: unit.producedBy.length,
395	  }));
396	}
