398	/**
399	 * Surface contradictions: two or more producers asserting incompatible contracts
400	 * (different signature or reuse verb) for the SAME unit_id. Never silently
401	 * resolved — the host reports both sides.
402	 *
403	 * @param {Array<Object>} units - Deduped units from dedupByUnit
404	 * @returns {Array<Object>} Contradiction records (unit_id, path, symbol, field, values)
405	 */
406	function detectContradictions(units) {
407	  const contradictions = [];
408	
409	  for (const unit of units) {
410	    if (unit.producedBy.length < 2) {
411	      continue;
412	    }
413	    for (const field of ['signatureByProducer', 'reuseByProducer']) {
414	      const distinct = new Set(
415	        Object.values(unit[field]).map((v) => normalizeText(v)).filter(Boolean),
416	      );
417	      if (distinct.size > 1) {
418	        contradictions.push({
419	          unit_id: unit.unit_id,
420	          path: unit.path,
421	          symbol: unit.symbol,
422	          field: field.replace('ByProducer', ''),
423	          values: Object.fromEntries(
424	            Object.entries(unit[field]).filter(([, v]) => normalizeText(v)),
425	          ),
426	        });
427	      }
428	    }
429	  }
430	
431	  return contradictions;
432	}
