434	/**
435	 * Build the agreement-weighted findings registry from deduped units.
436	 *
437	 * @param {Array<Object>} units - Deduped units
438	 * @param {Object} options - { relevanceGate, agreementMin }
439	 * @returns {Object} Registry buckets + lowConfidence + contradictions + metrics
440	 */
441	function buildRegistry(units, options) {
442	  const relevanceGate = isFiniteNumber(options.relevanceGate) ? options.relevanceGate : DEFAULT_RELEVANCE_GATE;
443	  const agreementMin = isFiniteNumber(options.agreementMin) ? options.agreementMin : DEFAULT_AGREEMENT_MIN;
444	
445	  const registry = {
446	    reuseCandidates: [],
447	    integrationPoints: [],
448	    conventions: [],
449	    dependencies: [],
450	    gaps: [],
451	    lowConfidence: [],
452	    contradictions: detectContradictions(units),
453	  };
454	
455	  const toRecord = (unit) => ({
456	    unit_id: unit.unit_id,
457	    path: unit.path,
458	    symbol: unit.symbol,
459	    kind: unit.kind,
460	    signature: unit.signature,
461	    reuse: unit.reuse,
462	    evidence: unit.evidence,
463	    notes: unit.notes,
464	    producedBy: unit.producedBy.slice().sort(),
465	    agreement: unit.agreement,
466	    agreementEligible: unit.agreement >= agreementMin,
467	    relevance: Math.round(unit.maxRelevance * 1000) / 1000,
468	    firstIteration: unit.firstIteration,
469	  });
470	
471	  let agreementEligibleCount = 0;
472	  let relevanceFloorPassCount = 0;
473	
474	  for (const unit of units) {
475	    const record = toRecord(unit);
476	
477	    // Relevance gate: below-gate units drop to the low-confidence bucket (kept,
478	    // not discarded, so the report's Gaps section can surface near-misses).
479	    if (unit.maxRelevance < relevanceGate) {
480	      registry.lowConfidence.push({ ...record, droppedBelowGate: relevanceGate });
481	      continue;
482	    }
483	    relevanceFloorPassCount += 1;
484	    if (record.agreementEligible) {
485	      agreementEligibleCount += 1;
486	    }
487	
488	    const bucket = KIND_TO_BUCKET[unit.kind] || 'reuseCandidates';
489	    registry[bucket].push(record);
490	  }
491	
492	  // Stable ordering: agreement desc, then relevance desc, then path.
493	  const sortRecords = (records) => records.sort((a, b) =>
494	    b.agreement - a.agreement
495	    || b.relevance - a.relevance
496	    || a.path.localeCompare(b.path)
497	    || a.symbol.localeCompare(b.symbol));
498	  for (const bucket of Object.keys(KIND_TO_BUCKET)) {
499	    sortRecords(registry[KIND_TO_BUCKET[bucket]]);
500	  }
501	  sortRecords(registry.lowConfidence);
502	
503	  const gatedCount = relevanceFloorPassCount;
504	  const totalUnits = units.length;
505	
506	  registry.metrics = {
507	    findings: totalUnits,
508	    gatedFindings: gatedCount,
509	    lowConfidenceFindings: registry.lowConfidence.length,
510	    agreementEligible: agreementEligibleCount,
511	    contradictions: registry.contradictions.length,
512	    // agreementRate over gated finding-kind units (matches the graph signal's intent).
513	    agreementRate: gatedCount > 0 ? Math.round((agreementEligibleCount / gatedCount) * 1000) / 1000 : 0,
514	    relevanceFloor: totalUnits > 0 ? Math.round((gatedCount / totalUnits) * 1000) / 1000 : 0,
515	    reuseCandidates: registry.reuseCandidates.length,
516	    integrationPoints: registry.integrationPoints.length,
517	    conventions: registry.conventions.length,
518	    dependencies: registry.dependencies.length,
519	    gaps: registry.gaps.length,
520	  };
521	
522	  return registry;
523	}
